import React, { useState } from 'react';
import Web3 from 'web3';
import contractABI from './YourContractABI'; // Contract ABI should be imported here

const App = () => {
  const [account, setAccount] = useState(null);
  const [contract, setContract] = useState(null);

  const loadWeb3 = async () => {
    if (window.ethereum) {
      window.web3 = new Web3(window.ethereum);
      await window.ethereum.enable();
      setAccount(await web3.eth.getAccounts());
    } else {
      console.log('Non-Ethereum browser detected. You should consider trying MetaMask!');
    }
  };

  const loadContract = async () => {
    const accounts = await web3.eth.getAccounts();
    const networkId = await web3.eth.net.getId();
    const contractAddress = 'YourContractAddress'; // Contract address should be specified here
    const contractInstance = new web3.eth.Contract(contractABI, contractAddress);
    setContract(contractInstance);
  };

  const callContractFunction = async () => {
    if (account && contract) {
      const txParameters = {
        from: account[0], // use the first account in accounts array
        gas: '6721975',
        // gasPrice: 'YourGasPrice',
      };

      const receipt = await contract.methods.yourContractFunction().send(txParameters);
      console.log(`Transaction receipt`, receipt);
    } else {
      console.log('Account and contract are not ready.');
    }
  };

  return (
    <div>
      <button onClick={loadWeb3}>Connect to MetaMask</button>
      <button onClick={loadContract}>Load Contract</button>
      <button onClick={callContractFunction}>Call Contract Function</button>
    </div>
  );
};

export default App;